function _parseLine(
    string memory expectedPrefix,
    string memory stdout,
    bool required
) private returns (string memory) {
    Vm vm = Vm(Utils.CHEATCODE_ADDRESS);
    if (vm.contains(stdout, expectedPrefix)) {
        // Get the substring after the prefix
        string[] memory segments = vm.split(stdout, expectedPrefix);
        if (segments.length > 2) {
            revert(
                string(
                    abi.encodePacked(
                        "Found multiple occurrences of prefix '",
                        expectedPrefix,
                        "' in output: ",
                        stdout
                    )
                )
            );
        }
        string memory suffix = segments[1];
        // Keep only the first line
        return vm.split(suffix, "\n")[0];
    } else if (required) {
        revert(
            string(abi.encodePacked("Failed to find line with prefix '", expectedPrefix, "' in output: ", stdout))
        );
    } else {
        return "";
    }
}

function claimFee(
    DistributionInfo calldata info,
    address payable recipient
) public nonReentrant {
    // DistributionInfo must be correct for this distribution ID.
    DistributionState storage state = _distributionStates[info.party][info.distributionId];
    if (state.distributionHash != _getDistributionHash(info)) {
        revert InvalidDistributionInfoError(info);
    }
    // Caller must be the fee recipient.
    if (info.feeRecipient != msg.sender) {
        revert OnlyFeeRecipientError(msg.sender, info.feeRecipient);
    }
    // Must not have claimed the fee yet.
    if (state.wasFeeClaimed) {
        revert DistributionFeeAlreadyClaimedError(info.distributionId);
    }
    // Mark the fee as claimed.
    state.wasFeeClaimed = true;
    // Transfer the tokens owed.
    _transfer(info.tokenType, info.token, recipient, info.fee);
    emit DistributionFeeClaimed(
        info.party,
        info.feeRecipient,
        info.tokenType,
        info.token,
        info.fee
    );
}

function seizeAllowed(
    address mTokenCollateral,
    address mTokenBorrowed,
    address liquidator,
    address borrower,
    uint seizeTokens
) external override returns (uint) {
    // Pausing is a very serious situation - we revert to sound the alarms
    require(!seizeGuardianPaused, "seize is paused");

    // Shh - currently unused
    seizeTokens;

    if (
        !markets[mTokenCollateral].isListed ||
        !markets[mTokenBorrowed].isListed
    ) {
        return uint(Error.MARKET_NOT_LISTED);
    }

    if (
        MToken(mTokenCollateral).comptroller() !=
        MToken(mTokenBorrowed).comptroller()
    ) {
        return uint(Error.COMPTROLLER_MISMATCH);
    }

    // Keep the flywheel moving
    // Note: We don't update borrower indices here because as part of liquidations
    //       repayBorrowFresh is called, which in turn calls `borrowAllow`, which updates
    //       the liquidated borrower's indices.
    updateAndDistributeSupplierRewardsForToken(mTokenCollateral, borrower);
    updateAndDistributeSupplierRewardsForToken(
        mTokenCollateral,
        liquidator
    );

    return uint(Error.NO_ERROR);
}

function _distribute(address tokenAddress) private onlyWhenNotFrozen nonReentrant {
  require(
    ignoreRenaming_carbonFeeBeneficiary != address(0),
    "Can't distribute to the zero address"
  );
  TokenState storage tokenState = tokenStates[tokenAddress];

  FixidityLib.Fraction
    memory totalFractionOfOtherBeneficiariesAndCarbonFixidity = getTotalFractionOfOtherBeneficiariesAndCarbonFixidity();

  uint256 carbonFundAmount = _calculateDistributeAmounts(
    getCarbonFractionFixidity(),
    totalFractionOfOtherBeneficiariesAndCarbonFixidity,
    tokenState.toDistribute
  );

  _executePayment(tokenAddress, ignoreRenaming_carbonFeeBeneficiary, carbonFundAmount);

  for (uint256 i = 0; i < EnumerableSet.length(otherBeneficiariesAddresses); i++) {
    address beneficiary = otherBeneficiariesAddresses.get(i);
    Beneficiary storage otherBeneficiary = otherBeneficiaries[beneficiary];

    uint256 amount = _calculateDistributeAmounts(
      otherBeneficiary.fraction,
      totalFractionOfOtherBeneficiariesAndCarbonFixidity,
      tokenState.toDistribute
    );

    _executePayment(tokenAddress, beneficiary, amount);
  }

  tokenState.toDistribute = 0;
}

function proposeUpgrade(
    address proxyAddress,
    address proxyAdminAddress,
    address newImplementationAddress,
    string memory newImplementationContractName,
    Options memory opts
) internal returns (ProposeUpgradeResponse memory) {
    Vm vm = Vm(Utils.CHEATCODE_ADDRESS);

    string memory outDir = Utils.getOutDir();
    ContractInfo memory contractInfo = Utils.getContractInfo(newImplementationContractName, outDir);

    string[] memory inputs = buildProposeUpgradeCommand(
        proxyAddress,
        proxyAdminAddress,
        newImplementationAddress,
        contractInfo,
        opts
    );

    Vm.FfiResult memory result = Utils.runAsBashCommand(inputs);
    string memory stdout = string(result.stdout);

    if (result.exitCode != 0) {
        revert(
            string(
                abi.encodePacked(
                    "Failed to propose upgrade for proxy ",
                    vm.toString(proxyAddress),
                    ": ",
                    string(result.stderr)
                )
            )
        );
    }

    return parseProposeUpgradeResponse(stdout);
}

function _upgradeToAndCallSecure(
    address newImplementation,
    bytes memory data,
    bool forceCall
) internal {
    address oldImplementation = _getImplementation();

    // Initial upgrade and setup call
    _setImplementation(newImplementation);
    if (data.length > 0 || forceCall) {
        Address.functionDelegateCall(newImplementation, data);
    }

    // Perform rollback test if not already in progress
    StorageSlot.BooleanSlot storage rollbackTesting = StorageSlot.getBooleanSlot(_ROLLBACK_SLOT);
    if (!rollbackTesting.value) {
        // Trigger rollback using upgradeTo from the new implementation
        rollbackTesting.value = true;
        Address.functionDelegateCall(
            newImplementation,
            abi.encodeWithSignature("upgradeTo(address)", oldImplementation)
        );
        rollbackTesting.value = false;
        // Check rollback was effective
        require(oldImplementation == _getImplementation(), "ERC1967Upgrade: upgrade breaks further upgrades");
        // Finally reset to the new implementation and log the upgrade
        _upgradeTo(newImplementation);
    }
}

function createMultipleWinners(
  PrizePool prizePool,
  MultipleWinnersConfig memory prizeStrategyConfig,
  uint8 decimals,
  address owner
) external returns (MultipleWinners) {
  MultipleWinners mw = multipleWinnersProxyFactory.create();

  Ticket ticket = _createTicket(
    prizeStrategyConfig.ticketName,
    prizeStrategyConfig.ticketSymbol,
    decimals,
    prizePool
  );

  ControlledToken sponsorship = _createSponsorship(
    prizeStrategyConfig.sponsorshipName,
    prizeStrategyConfig.sponsorshipSymbol,
    decimals,
    prizePool
  );

  mw.initializeMultipleWinners(
    prizeStrategyConfig.prizePeriodStart,
    prizeStrategyConfig.prizePeriodSeconds,
    prizePool,
    ticket,
    sponsorship,
    prizeStrategyConfig.rngService,
    prizeStrategyConfig.numberOfWinners
  );

  mw.setPrizeSplits(prizeStrategyConfig.prizeSplits);

  if (prizeStrategyConfig.splitExternalErc20Awards) {
    mw.setSplitExternalErc20Awards(true);
  }

  mw.transferOwnership(owner);

  emit MultipleWinnersCreated(address(mw));

  return mw;
}

function _acceptImplementation() public returns (uint) {
    // Check caller is pendingImplementation and pendingImplementation ≠ address(0)
    if (
        msg.sender != pendingComptrollerImplementation ||
        pendingComptrollerImplementation == address(0)
    ) {
        return
            fail(
                Error.UNAUTHORIZED,
                FailureInfo.ACCEPT_PENDING_IMPLEMENTATION_ADDRESS_CHECK
            );
    }

    // Save current values for inclusion in log
    address oldImplementation = comptrollerImplementation;
    address oldPendingImplementation = pendingComptrollerImplementation;

    comptrollerImplementation = pendingComptrollerImplementation;

    pendingComptrollerImplementation = address(0);

    emit NewImplementation(oldImplementation, comptrollerImplementation);
    emit NewPendingImplementation(
        oldPendingImplementation,
        pendingComptrollerImplementation
    );

    return uint(Error.NO_ERROR);
}

function excessivelySafeStaticCall(
    address _target,
    uint _gas,
    uint16 _maxCopy,
    bytes memory _calldata
) internal view returns (bool, bytes memory) {
    // set up for assembly call
    uint _toCopy;
    bool _success;
    bytes memory _returnData = new bytes(_maxCopy);
    // dispatch message to recipient
    // by assembly calling "handle" function
    // we call via assembly to avoid memcopying a very large returndata
    // returned by a malicious contract
    assembly {
        _success := staticcall(
            _gas, // gas
            _target, // recipient
            add(_calldata, 0x20), // inloc
            mload(_calldata), // inlen
            0, // outloc
            0 // outlen
        )
        // limit our copy to 256 bytes
        _toCopy := returndatasize()
        if gt(_toCopy, _maxCopy) {
            _toCopy := _maxCopy
        }
        // Store the length of the copied bytes
        mstore(_returnData, _toCopy)
        // copy the bytes from returndata[0:_toCopy]
        returndatacopy(add(_returnData, 0x20), 0, _toCopy)
    }
    return (_success, _returnData);
}
